INSERT IGNORE INTO `sys_texts` (`id`, `alias`, `lang`, `context`) VALUES
(1, 'no_timezone_detected', 'ru', 'Нам не удалось определить местоположение. Возможно, вы ввели название города с ошибкой. Если вы считаете, что вы не ошиблись, то можете в следующем сообщении указать ваш часовой пояс самостоятельно в формате UTC-1, UTC, UTC+1. Либо напишите название города заново. Также вы можете написать пропустить, и тогда вашим часовым поясом будет нулевой часовой пояс UTC, проходящий через нулевой меридиан.'),
(2, 'msk', 'ru', 'Московское время'),
(3, 'msk_plus_1', 'ru', 'Московское время плюс {#HOUR#} час'),
(4, 'msk_minus_1', 'ru', 'Московское время минус {#HOUR#} час'),
(5, 'msk_plus_2', 'ru', 'Московское время плюс {#HOUR#} часа'),
(6, 'msk_minus_2', 'ru', 'Московское время минус {#HOUR#} часа'),
(7, 'msk_plus_5', 'ru', 'Московское время плюс {#HOUR#} часов'),
(8, 'msk_minus_5', 'ru', 'Московское время минус {#HOUR#} часов'),
(9, 'service_to_detect_city_not_available', 'ru', 'Сервис по определению местоположения населённого пункта не доступен. Попробуйте позже.'),
(10, 'city_not_exists', 'ru', 'Не удалось найти такой населённый пункт.'),
(11, 'free', 'ru', 'Бесплатный'),
(12, 'greeting', 'ru', 'Привет! Я бот, который поможет вам организовать жизнь. Я умею создавать списки, напоминать о событиях, вести задачи и дневники, помогу собраться в поездку и напомню о том, что вам понравилась или не понравилась та или иная еда/бренд/место/т.п., если вы добавите заметку об этом. У меня много и других функций...\n\nНо для начала давайте настроем бота. Введите, как мне обращаться к вам (по умолчанию: \"Друг\"):'),
(13, 'free_descr', 'ru', 'Бесплатный тариф, на котором можно ознакомиться с сервисом в урезанном виде. На этом тарифе доступно создание и управление списками, задачами, заметками, дневниками, напоминаниями в пошаговом режиме.\n\nЧтобы открыть доступ к хранению файлов и искусственному интеллекту, способному управлять всем этим в режиме диалога, необходимо приобрести платный тариф.'),
(14, 'gift', 'ru', 'Подарочный'),
(16, 'gift_descr', 'ru', 'Подарочный тариф, на котором можно ознакомиться с сервисом в полном виде. На нём доступно создание и управление списками, задачами, заметками, дневниками, напоминаниями пошагово.\n\nА также открыт доступ к хранению файлов и искусственному интеллекту, способному управлять всем этим в режиме диалога, что ускоряет и упрощает создание всех сущностей.'),
(17, 'no_user_found', 'ru', 'Неизвестная ошибка. Мы уже в курсе и стараемся решить проблему как можно скорее.'),
(18, 'current_tariff_informer', 'ru', 'Ваш текущий тариф: \"{#TARIFF#}\".\n\nОписание тарифа:\n{#DESCRIPTION#}\n\nХотите узнать о другом тарифе или сменить его, выберите из следующих:'),
(19, 'choose_tariff_informer', 'ru', 'Вы просматриваете информацию о тарифе: \"{#TARIFF#}\".\n\nОписание тарифа:\n{#DESCRIPTION#}\n\nЕсли вы хотите подключить его, нажмите на \"Подключить\". Стоимость тарифа {#COST#}/мес.\n\n{#ACTION#}'),
(20, 'connect', 'ru', 'Подключить'),
(21, 'return_back', 'ru', 'Вернуться назад'),
(22, 'cancel', 'ru', '❌ Завершить'),
(23, 'action_canceled', 'ru', 'Действие прервано.'),
(24, 'unknown_command', 'ru', 'К сожалению, я не понимаю вас. Возможно вы хотите выполнить команду из другого сценария. Отмените текущий сценарий, нажав на соответствующую кнопку Завершения, чтобы перейти к другим командам.'),
(25, 'back', 'ru', '⬅ Назад'),
(26, 'greeting_no_agree', 'ru', 'Привет!\n\nЯ бот, который поможет вам организовать жизнь. Я умею создавать списки, напоминать о событиях, вести задачи и дневники, помогу собраться в поездку и напомню о том, что вам понравилась или не понравилась та или иная еда/бренд/место/т.п., если вы добавите заметку об этом. У меня много и других функций...\n\nНо для начала давайте настроем бота под вас. И первым пунктом подтвердите, что вы согласны с политиками конфиденциальности и обработки персональных данных. В любой момент вы можете отозвать согласие, удалятся при этом безвозвратно все ваши данные из нашего сервиса.'),
(27, 'yes', 'ru', '✅ Да'),
(28, 'no', 'ru', '❌ Нет'),
(29, 'change_tariff_confirmation', 'ru', '<b>Необходимо подтверждение смены тарифа с {#OLD_TARIFF#} на {#NEW_TARIFF#}.</b>\n\nПодтвердите?\n\n<i>Неиспользованные минуты старого тарифа сохранятся и старый тариф активируется сразу после истечения срока нового тарифа, если новый не продлится.</i>'),
(30, 'tariff_was_changed', 'ru', 'Тариф был изменён на: \"{#TARIFF#}\".\r\n\r\nОписание тарифа:\r\n{#DESCRIPTION#}\r\n'),
(31, 'tariff_buy_url', 'ru', 'Выбранный тариф \"{#TARIFF#}\", чтобы он применился, необходимо оплатить, прейдя по ссылке на сайт банка ВТБ: <a href=\"{#URL#}\">{#URL#}</a>. Ссылка действует 20 минут. После чего вам необходимо будет создать новую оплату.\n\nОписание тарифа:\n{#DESCRIPTION#}'),
(32, 'tariff_bought', 'ru', 'Был успешно приобретён и подключён тариф \"{#TARIFF#}\".\r\n\r\nОписание тарифа:\r\n{#DESCRIPTION#}'),
(33, 'agreed_on_privacy_politics', 'ru', 'Политика конфиденциальности принята и теперь вы можете пользоваться ботом.'),
(34, 'disagreed_on_privacy_politics', 'ru', 'Без принятия Политики конфиденциальности невозможно воспользоваться сервисом.'),
(35, 'confirm_agreement_with_politics', 'ru', 'Чтобы пользоваться ботом необходимо согласие с <a href=\"{#URL#}\">Политикой конфиденциальности в отношении обработки персональных данных</a>. При создании бота выполнялись требования законодательства РФ к хранению и обработке персональных данных. Ваши данные в надежных руках. Подтвердить своё согласие?'),
(36, 'confirm_agreement_with_politics_start', 'ru', 'Это мастер настройки бота, но перед тем, как перейти к настройке необходимо дать согласие с <a href=\"{#URL#}\">Политикой конфиденциальности в отношении обработки персональных данных</a>. При создании бота выполнялись требования законодательства РФ к хранению и обработке персональных данных. Ваши данные в надежных руках. Подтвердить своё согласие?'),
(37, 'unknown_command_no_step_bot', 'ru', 'К сожалению, я не понимаю вас. Попробуй воспользоваться меню команд'),
(38, 'list_start_promo', 'ru', 'Вы можете создавать разные списки прямо здесь:\n• 🛒 продукты\n• 🎁 подарки\n• 🎬 фильмы к просмотру\n• ✈️ вещи в дорогу и т.д.\n\n✨ Во всех платных тарифах доступно создание, поиск и удаление списков через искусственный интеллект, когда можно просто написать сообщение боту в свободной форме (например, «создай список подарков конфеты, цветы, духи» или «список покупок молоко, хлеб, сыр», или «найди список покупок для Ozon»), и список найдётся или создастся автоматически, ему сгенерируется подходящее название и теги.'),
(39, 'list_enter_name', 'ru', 'Введите название для вашего нового списка и отправьте его боту.'),
(40, 'list_start', 'ru', 'Выберите, что вы хотите сделать: создать или найти список из уже созданных вами.'),
(41, 'create_list', 'ru', 'Создать список'),
(42, 'find_list', 'ru', 'Найти список'),
(43, 'list_enter_items', 'ru', 'Введите элементы списка через запятую или каждый с новой строки (оба формата нельзя использовать) и отправьте боту.\n\nЕсли элементы списка - это предложения с запятыми, вводите каждое предложения с новой строки. Если в тексте есть переводы строк, то они будут использоваться как маркер для начала нового элемента списка.\n\nВаш список:'),
(45, 'list_enter_tags', 'ru', 'Чтобы список легче искался, введите теги для него через запятую. Например, если это список покупок в конкретном магазине, введите слово \"покупки\" и название магазина. Вы можете пропустить этот пункт.\n\nВаши теги: {#TAGS#}'),
(46, 'list_was_created_ask', 'ru', 'Вы создали список \"{#TITLE#}\":\n\n{#LIST#}\n\n{#TAGS#}\n\nХотите ли вы привязать его к другой сущности?'),
(47, 'list_was_created', 'ru', 'Вы создали список \"{#TITLE#}\":\n\n{#LIST#}\n\n{#TAGS#}'),
(48, 'list_change_name', 'ru', 'Введите новое название для вашего списка и отправьте его боту. Старое название: {#TITLE#}'),
(49, 'skip', 'ru', '⏩ Пропустить'),
(50, 'no_list_created', 'ru', 'Список не создан.'),
(51, 'delete_list_items', 'ru', 'Режим удаления списка\r\n{#LIST#}\r\n\r\nБудьте осторожны, удаление происходит безвозвратно. Введите номер элемента из списка, который необходимо удалить:'),
(52, 'editing_list_items', 'ru', 'Введите новый текст для элемента списка:'),
(53, 'wrong_list_item_number', 'ru', 'Вы ввели неправильный номер элемента списка, попробуйте еще раз.'),
(54, 'remind', 'ru', 'Напоминание'),
(55, 'task', 'ru', 'Задача'),
(56, 'memory', 'ru', 'Заметка'),
(57, 'person', 'ru', 'Человек'),
(58, 'place', 'ru', 'Локация/Место'),
(59, 'travel', 'ru', 'Путешествие'),
(60, 'diary', 'ru', 'Дневник'),
(61, 'schedule', 'ru', 'Расписание'),
(62, 'file', 'ru', 'Файл'),
(63, 'enter_edit_list_item', 'ru', 'Введите новое значение для пункта списка.\n\nСтарое значение: \"{#ITEM#}\"'),
(64, 'edit_list_item_success', 'ru', 'Список успешно отредактирован.'),
(65, 'list_enter_items_with_old', 'ru', 'Ваш список:\n\n{#LIST#}\n\nВведите дополнительные элементы списка и отправьте их или воспользуйтесь кнопками в сообщении. Элементы списка необходимо вводить через запятую или каждый с новой строки (оба формата нельзя использовать).'),
(66, 'edit', 'ru', '✏️ Редактировать'),
(67, 'list_not_exists_for_edit', 'ru', 'Вы редактируете несуществующий список'),
(68, 'edit_list_items', 'ru', 'Режим редактирования списка\n{#LIST#}\n\nВведите номер элемента из списка, который необходимо отредактировать:'),
(69, 'list_item_deleted_successfully', 'ru', 'Элемент списка \"{#ITEM#}\" удалён.'),
(70, 'delete', 'ru', '✂️ Удаление'),
(72, 'delete_list_items_btn', 'ru', '✂️ Удаление элементов списка'),
(73, 'edit_list_items_btn', 'ru', '✏️ Редактирование элементов списка'),
(74, 'list_action_choose', 'ru', 'Выберите, что вы хотите сделать: создать список или найти его. \n\nНажмите на один из вариантов ниже:'),
(75, 'wrong_list_tag_number', 'ru', 'Вы ввели неправильный номер тега, попробуйте еще раз.'),
(76, 'enter_edit_list_tag', 'ru', 'Введите новое значение тега.\r\n\r\nСтарое значение: \"{#TAG#}\"'),
(77, 'edit_list_tag_success', 'ru', 'Тег успешно отредактирован.'),
(79, 'wrong_list_tag_new_title', 'ru', 'Произошла ошибка при редактировании тега. Попробуйте ещё раз.'),
(80, 'wrong_list_item_new_title', 'ru', 'Произошла ошибка при редактировании элемента списка. Попробуйте ещё раз.'),
(82, 'edit_list_tags_btn', 'ru', '✏️ Редактирование тегов'),
(83, 'delete_list_tags_btn', 'ru', '✂️ Удаление тегов'),
(85, 'edit_list_tags', 'ru', 'Режим редактирования тегов\r\n{#LIST#}\r\n\r\nВведите номер тега из списка, который необходимо отредактировать:'),
(87, 'delete_list_tags', 'ru', 'Режим удаления тегов\r\n{#LIST#}\r\n\r\nБудьте осторожны, удаление происходит безвозвратно. Введите номер тега из списка, который необходимо удалить:'),
(88, 'list_tag_deleted_successfully', 'ru', 'Тег \"{#ITEM#}\" успешно удалён.'),
(89, 'list_enter_search', 'ru', 'Введите и отправьте боту тег или фразу/слово из названия списка или его элементов, чтобы мы нашли ваш список. \n\nИли нажмите на кнопку: Показать все списки. Списки выводятся постранично, по {#AMOUNT#} шт.'),
(90, 'show_all_lists', 'ru', 'Показать все списки'),
(91, 'next', 'ru', '➡️ Следующий'),
(92, 'previous', 'ru', '⬅️ Предыдущий'),
(93, 'next_lists', 'ru', '➡️ Следующие {#AMOUNT#} списков'),
(94, 'previous_lists', 'ru', '⬅️ Предыдущие {#AMOUNT#} списков'),
(95, 'lists_show', 'ru', 'Это постраничный вывод всех ваших списков, чтобы вы могли найти нужный. Отправьте боту номер списка на странице или воспользуйтесь кнопками для пролистывания страниц.\n\nСтраница {#PAGE#}/{#MAXPAGE#}.\n\n{#LISTS#}\n'),
(96, 'lists_show_search', 'ru', 'Здесь 30 самых релевантных результатов для вашего поиска. Отправьте боту номер списка, чтобы открыть его.\r\n\r\n{#LISTS#}\r\n'),
(97, 'too_short_list_search_message', 'ru', 'Слишком короткий текст для поиска. Минимальное количество символов: 3.'),
(98, 'no_lists_in_search_json', 'ru', 'Нет доступных списков.'),
(99, 'wrong_number_on_page', 'ru', 'Неверный номер элемента на странице.'),
(100, 'list_found', 'ru', 'Ваш список \"{#TITLE#}\":\r\n\r\n{#LIST#}\r\n\r\nТеги: {#TAGS#}'),
(101, 'no_lists_found', 'ru', 'Не найдено ни одного списка...'),
(102, 'list_was_deleted_successfully', 'ru', 'Ваш список \"{#TITLE#}\" был успешно удалён. \r\n\r\n{#LIST#}\r\n\r\nТеги: {#TAGS#}'),
(103, 'list_was_edited', 'ru', 'Список был успешно обновлён.'),
(104, 'no_list_edited', 'ru', 'Список был удалён'),
(106, 'list_was_edited_ask', 'ru', 'Вы отредактировали список \"{#TITLE#}\":\r\n\r\n{#LIST#}\r\n\r\n{#TAGS#}\r\n\r\nХотите ли вы привязать его к другой сущности?'),
