(371, 'task_was_created', 'ru', 'Вы создали {#TYPE#} ({#SUBTYPE#}): \"{#TITLE#}\".\n{#DESCRIPTION#}{#TAGS#}{#DEADLINE#}{#REPEAT#}{#REMINDERS#}'),
