(493, 'telegram_task_action_choose', 'ru', '<b>Выберите действие</b>\n<i>Что вы хотите сделать?</i>'),
(494, 'telegram_task_change_type', 'ru', '<b>Изменить тип</b>\r\n<i>Текущий: {#TYPE#}</i>'),
(495, 'telegram_task_choose_task_cath', 'ru', '<b>Выберите подтип задачи</b>\n<i>Нажмите на подходящий вариант</i>\n\n<blockquote expandable>\n<b>Подробное описание подтипов:</b>\n🛒 Покупки — продукты, лекарства и т.п.\n💳 Платёж — счета, налоги, кредитные платежи и т.п.\n🧹 Уборка/быт — полить цветы, помыть плиту и т.д.\n📞 Позвонить — клиенту, близким и т.д.\n✉️ Написать — письмо, сообщение и т.п.\n📖 Учёба — занятия, экзамены и т.п.\n📊 Отчёт/Показания — отчёты в налоговую, показания счётчиков и т.п.\n⏳ Дедлайн — задача с фиксированным сроком\n✅ Другое — всё остальное\n</blockquote>'),
(496, 'telegram_task_choose_event_cath', 'ru', '<b>Выберите подтип события</b>\n<i>Нажмите на подходящий вариант</i>\n\n<blockquote expandable>\n<b>Подробное описание подтипов:</b>\n🤝 Встреча → личная или рабочая встреча, звонок по видеосвязи, собрание и т.п.\n🎂 День рождения → как сам факт, что в этот день кто-то родился, так и может быть каким-то разовым мероприятием.\n🎉 Праздник → торжественное или праздничное мероприятие: свадьба, корпоратив, вечеринка, фестиваль.\n✈️ Поездка → поездка, путешествие, командировка.\n📅 Годовщина → памятная дата, например, свадьбы, начала работы, события.\n💊 Лекарство → приём лекарств в конкретное время.\n🐕 Выгул/прогулка → время прогулки с собакой или кем-то другим.\n🏋️ Спорт → тренировка, зарядка, фитнес, занятия в зале, пробежка и т.п.\n🍽️ Приём пищи → завтрак, обед, ужин или перекус в конкретное время, если вы едите сами или кормите кого-то по часам.\n🏥 Приём/запись → запись ко врачу, парикмахеру, на процедуру и т.п.\n📅 Другое → любые важные события, которые не подходят под другие категории (сюда в том числе можно отнести похороны, суд, экзамен и т.п.).\n</blockquote>'),
(497, 'telegram_event_add_title', 'ru', '<b>Название события</b>\r\n<i>Введите короткое название и отправьте</i>\r\n\r\n<i>Примеры: Встреча с клиентом, День рождения друга</i>'),
(498, 'telegram_task_add_title', 'ru', '<b>Название задачи</b>\r\n<i>Введите короткое название и отправьте</i>\r\n\r\n<i>Примеры: Купить лекарства, Заплатить за интернет</i>'),
(499, 'telegram_task_add_description', 'ru', '<b>Описание задачи</b> <i>(необязательно)</i>\n<i>Введите и отправьте детали. Можно пропустить.</i>'),
(500, 'telegram_event_add_description', 'ru', '<b>Описание задачи</b> <i>(необязательно)</i>\r\n<i>Введите и отправьте детали. Можно пропустить.</i>'),
(501, 'telegram_task_change_title', 'ru', '<b>Изменить название задачи</b>\n<i>Введите новое название и отправьте</i>\n\n<b>Старое название:</b> {#TITLE#}'),
(502, 'telegram_event_change_title', 'ru', '<b>Изменить название события</b>\n<i>Введите новое название и отправьте</i>\n\n<b>Старое название:</b> {#TITLE#}'),
(503, 'telegram_task_change_task_cath', 'ru', '<b>Изменить подтип задачи</b>\n<i>Нажмите на подходящий вариант</i>\n\n<b>Ваш прошлый выбор:</b> {#TYPE#}\n\n<blockquote expandable>\n<b>Подробное описание подтипов:</b>\n🛒 Покупки — продукты, лекарства и т.п.\n💳 Платёж — счета, налоги, кредитные платежи и т.п.\n🧹 Уборка/быт — полить цветы, помыть плиту и т.д.\n📞 Позвонить — клиенту, близким и т.д.\n✉️ Написать — письмо, сообщение и т.п.\n📖 Учёба — занятия, экзамены и т.п.\n📊 Отчёт/Показания — отчёты в налоговую, показания счётчиков и т.п.\n⏳ Дедлайн — задача с фиксированным сроком\n✅ Другое — всё остальное\n</blockquote>');
INSERT IGNORE INTO `sys_texts` (`id`, `alias`, `lang`, `context`) VALUES
(504, 'telegram_task_change_event_cath', 'ru', '<b>Изменить подтип события</b>\r\n<i>Нажмите на подходящий вариант</i>\r\n\r\n<b>Ваш прошлый выбор:</b> {#TYPE#}\r\n\r\n<blockquote expandable>\r\n<b>Подробное описание подтипов:</b>\r\n🤝 Встреча → личная или рабочая встреча, звонок по видеосвязи, собрание и т.п.\r\n🎂 День рождения → как сам факт, что в этот день кто-то родился, так и может быть каким-то разовым мероприятием.\r\n🎉 Праздник → торжественное или праздничное мероприятие: свадьба, корпоратив, вечеринка, фестиваль.\r\n✈️ Поездка → поездка, путешествие, командировка.\r\n📅 Годовщина → памятная дата, например, свадьбы, начала работы, события.\r\n💊 Лекарство → приём лекарств в конкретное время.\r\n🐕 Выгул/прогулка → время прогулки с собакой или кем-то другим.\r\n🏋️ Спорт → тренировка, зарядка, фитнес, занятия в зале, пробежка и т.п.\r\n🍽️ Приём пищи → завтрак, обед, ужин или перекус в конкретное время, если вы едите сами или кормите кого-то по часам.\r\n🏥 Приём/запись → запись ко врачу, парикмахеру, на процедуру и т.п.\r\n📅 Другое → любые важные события, которые не подходят под другие категории (сюда в том числе можно отнести похороны, суд, экзамен и т.п.).\r\n</blockquote>'),
(505, 'telegram_task_change_description', 'ru', '<b>Редактировать описание</b>\r\n<i>Введите новые подробности. Старые будут перезаписаны. Скопируйте их в поле ввода, если хотите изменить частично.</i>\r\n\r\n<b>Старое описание:</b> {#DESCRIPTION#}'),
(506, 'telegram_task_add_tags', 'ru', '<b>Теги задачи</b> <i>(необязательно)</i>\n<i>Введите слова/словосочетания через запятую или с переводом строки и отправьте</i>'),
(507, 'telegram_event_add_tags', 'ru', '<b>Теги события</b> <i>(необязательно)</i>\n<i>Введите слова/словосочетания через запятую или с переводом строки и отправьте</i>'),
(508, 'telegram_set_repeating_type', 'ru', '<b>Повторяемость</b>\n<i>Выберите, будет задача/событие одноразовой или повторяющейся</i>\n\n🎯 <b>Одноразовая</b> — наступает один раз  \n👉 Пример: «Сходить ко врачу 10 октября в 15:00»\n\n🔁 <b>Повторяющаяся</b> — создаётся по алгоритму (через n дней, по дням недели или числам месяца)  \n👉 Пример: «Передавать показания счётчиков с 18 по 22 число каждого месяца»'),
(509, 'telegram_task_change_tags_2', 'ru', '<b>Изменить теги</b>\r\n<i>Выберите действие или введите и отправьте новые теги для полной замены.\r\nФормат: через запятую или каждый с новой строки.</i>\r\n\r\n<b>Текущие теги:</b>\r\n{#TAGS#}'),
(510, 'telegram_task_change_tags', 'ru', '<b>Теги</b>\n<i>- Выберите действие или \n- Введите и отправьте новые теги для полной замены. Формат: через запятую или каждый с новой строки.</i>\n\n<b>Текущие теги:</b>\n{#TAGS#}'),
(511, 'telegram_delete_tags', 'ru', '<b>Удаление тегов</b>\n<i>Удаление происходит безвозвратно</i>\n\n<b>Текущие теги:</b>\n{#TAGS#}\n\n<i>Введите номер тега, который нужно удалить, и отправьте</i>\n<i>Или нажмите «Назад», чтобы выйти из режима удаления</i>'),
(512, 'telegram_edit_tags', 'ru', '<b>Редактирование тегов</b>\r\n\r\n<b>Текущие теги:</b>\r\n{#TAGS#}\r\n\r\n<i>Введите номер тега, который хотите изменить, и отправьте</i>\r\n<i>Или нажмите «Назад», чтобы выйти из режима редактирования</i>'),
(513, 'telegram_enter_edit_tag', 'ru', '<b>Новое значение тега</b>\r\n<i>Введите новое значение и отправьте</i>\r\n\r\n<b>Старое:</b> \"{#TAG#}\"'),
(514, 'telegram_edit_tag_success', 'ru', '<i>Тег успешно отредактирован.</i>'),
(515, 'telegram_tag_deleted_successfully', 'ru', '<i>Тег \"{#TAG#}\" успешно удалён.</i>'),
(516, 'telegram_event_enter_date_or_period', 'ru', '<b>Тип даты</b>\r\n<i>Выберите, событие на один день или несколько (период)</i>\r\n\r\n🎯 <b>Один день</b> — событие происходит в конкретную дату  \r\n📅 <b>Временной период</b> — событие длится несколько дней'),
(517, 'telegram_task_enter_date_or_period', 'ru', '<b>Тип даты</b>\n<i>Выберите, будет ли задача/событие с конкретной датой или с периодом</i>\n\n🎯 <b>Дедлайн</b> — событие на один день или это крайний срок выполнения  \n📅 <b>Период</b> — событие или задача в рамках нескольких дней'),
(518, 'telegram_enter_deadline', 'ru', '<b>Дедлайн</b>\r\n<i>Введите дату выполнения (с временем или без)</i>\r\n\r\n<i>Примеры:</i>\r\n10.06.2030 18:00  \r\n10 июня 2030 в 18:00  \r\nиюнь 10, 18:00 — <i>будет выбран ближайший доступный день</i>'),
(519, 'telegram_enter_period_start', 'ru', '<b>Временной интервал</b>\n<i>Введите дату начала</i>\n\n<i>Примеры:</i>\n18.09.2025  \n18 сентября, 15:00'),
(520, 'telegram_enter_period_end_or_skip', 'ru', '<b>Временной интервал</b>\n<i>Введите дату окончания</i>\n\n<i>Примеры:</i>\n20.09.2030  \n20 сентября, 20:00\n\n<i>Можно пропустить, если начало периода - это дата без времени, например, если это задача на один день.</i>'),
(521, 'telegram_enter_edit_period_start', 'ru', '<b>Редактировать дату начала периода</b>\r\n<i>Введите новое значение и отправьте</i>\r\n\r\n<i>Примеры:</i>\r\n18.09.2030\r\n18 сентября - <i>возьмется ближайшая дата</i>  \r\n2030-09-18 10:00\r\n\r\n<b>Текущее значение:</b> {#DATE#}'),
(522, 'telegram_enter_edit_period_end_or_skip', 'ru', '<b>Редактировать дату окончания периода</b>\r\n<i>Введите новое значение и отправьте</i>\r\n\r\n<i>Примеры:</i>\r\n20.09.2030  \r\n20 сентября  \r\n2030-09-20 10:00\r\n\r\n<b>Текущее значение:</b> {#DATE#}\r\n'),
(523, 'telegram_enter_edit_deadline', 'ru', '<b>Редактировать дедлайн</b>\r\n<i>Введите новое значение даты и, если необходимо, времени и отправьте</i>\r\n\r\n<i>Примеры:</i>\r\n2030-06-10 18:00:00  \r\n10.06.2030 18:00  \r\n10 июня 2030 в 18:00  \r\nиюнь 10, 18:00\r\n\r\n<b>Текущее значение:</b>  {#DATE#}'),
(524, 'telegram_ask_reminder_interval', 'ru', '<b>Добавить напоминание</b> <i>(время)</i>\n<i>Выберите, за сколько времени до события напомнить</i>'),
(525, 'telegram_enter_number_for_hours', 'ru', '<b>Добавление напоминания</b> <i>(время)</i>\n<i>За сколько часов до события напомнить? Введите целое число и отправьте</i>'),
(526, 'telegram_enter_number_for_days', 'ru', '<b>Добавление напоминания</b> <i>(время)</i>\n<i>За сколько дней до события напомнить? Введите целое число и отправьте</i>'),
(527, 'telegram_enter_number_for_weeks', 'ru', '<b>Добавление напоминания</b> <i>(время)</i>\n<i>За сколько недель до события напомнить? Введите целое число и отправьте</i>'),
(528, 'telegram_enter_number_for_months', 'ru', '<b>Добавление напоминания</b> <i>(время)</i>\n<i>За сколько месяцев до события напомнить? Введите целое число и отправьте</i>'),
(529, 'telegram_enter_optional_reminder_text', 'ru', '<b>Добавление напоминания</b> <i>(текст)</i>\n<i>Введите текст для напоминания (например: «Позвонить маме», «Купить подарок»). Можно пропустить</i>'),
(530, 'telegram_delete_reminders_step', 'ru', '<b>Удаление напоминания</b>\r\n<i>Удаление происходит безвозвратно</i>\r\n\r\n{#REMINDERS#}\r\n\r\n<i>Введите номер напоминания, которое хотите удалить, и отправьте</i>'),
(531, 'telegram_remind_deleted_successfully', 'ru', '<i>Напоминание успешно удалено.</i>'),
(532, 'telegram_wrong_reminder_number', 'ru', '<i>Вы ввели неправильный номер напоминания, попробуйте еще раз.</i>'),
(534, 'telegram_task_was_created', 'ru', '<b>{#TYPE#} создана</b> <i>({#SUBTYPE#})</i>\n\n<i>Название:</i> \"{#TITLE#}\".\n{#DESCRIPTION#}{#TAGS#}{#DEADLINE#}{#REPEAT#}{#REMINDERS#}\n'),
(535, 'telegram_task_was_created_ask', 'ru', '<b>Проверьте информацию по {#TYPE#}</b> <i>({#SUBTYPE#})</i>\n\n<i>Название:</i> \"{#TITLE#}\".\n{#DESCRIPTION#}{#TAGS#}{#DEADLINE#}{#REPEAT#}{#REMINDERS#}\n\n<b>Привязка к другой сущности</b>\n<i>Хотите привязать задачу к списку, заметке, человеку, дневнику или другому объекту?</i>'),
(536, 'telegram_no_repeat_choosen', 'ru', 'разовый, без повторов.'),
(537, 'telegram_daily_choosen', 'ru', 'ежедневный.'),
(538, 'task_pl_tv', 'ru', 'Задачами'),
(539, 'event_pl_tv', 'ru', 'Событиями'),
(541, 'telegram_week_days_choosen', 'ru', 'по дням недели: {#DAYS#}.'),
(542, 'telegram_month_days_choosen', 'ru', 'по следующим датам каждого месяца: {#DAYS#}.'),
(543, 'telegram_quarterly_deadline_chosen', 'ru', 'от начала квартала до {#DAY#}-го дня {#MONTH#}-го месяца каждого квартала.'),
(544, 'telegram_quarterly_period_chosen', 'ru', 'с {#START_DAY#}-го дня {#START_MONTH#}-го месяца квартала до {#END_DAY#}-го дня {#END_MONTH#}-го месяца квартала.'),
(545, 'telegram_yearly_deadline_chosen', 'ru', 'от начала года до {#DAY#}-го дня {#MONTH#}-го месяца каждого года.'),
(546, 'telegram_yearly_period_chosen', 'ru', 'с {#START_DAY#}-го дня {#START_MONTH#}-го месяца до {#END_DAY#}-го дня {#END_MONTH#}-го месяца каждого года.'),
(547, 'telegram_task_choose_type', 'ru', '<b>Что вы хотите создать?</b>\r\n\r\n✅ <i>Задача</i> — действие, которое нужно выполнить (например: позвонить, купить, написать)  \r\n📅 <i>Событие</i> — с конкретной датой/временем (например: встреча, день рождения, поездка)'),
(548, 'telegram_choose_week_days', 'ru', '<b>Выберите дни недели</b>\n<i>Галками отмечены уже выбранные дни</i>'),
(549, 'telegram_choose_at_least_one_day', 'ru', '<i>Выберите хотя бы один день недели.</i>'),
(550, 'telegram_ask_weekly_repeats_need_time', 'ru', '<b>Добавить время?</b>\r\n<i>Время нужно, если есть конкретные часы (например, занятие, приём у врача, тренировка).</i>\r\n\r\n<i>Можно:</i>\r\n• указать одно время для всех дней  \r\n• указать разное время для каждого дня  \r\n• не указывать время'),
(551, 'telegram_add_time_or_period', 'ru', '<b>Время события</b>\n<i>Укажите время начала (например: 10:00)</i>\n\n<i>Если нужно, добавьте время окончания через дефис (минус): 10:00–12:00. Это поможет мне предупредить вас о пересечении с другими событиями.</i>'),
(552, 'telegram_weekly_different_time', 'ru', '<b>Время события для <i>{#DAY#}</i></b>\n<i>Укажите время начала (например: 10:00)</i>\n\n<i>Если нужно, добавьте время окончания через дефис (минус): 10:00–12:00. Это поможет мне предупредить вас о пересечении с другими событиями.</i>'),
(553, 'telegram_enter_month_days', 'ru', '<b>Дни месяца</b>\n<i>Введите числа от 1 до 31 и отправьте</i>\n\n<i>Формат:</i> через запятую — отдельные дни, через дефис — период  \n<i>Пример:</i> 1, 5, 12-15, 25-31\n\n<blockquote expandable>\nЕсли указанного дня нет в месяце (например, 31 апреля), будет использована последняя дата месяца:\n• апрель → 30  \n• февраль → 28 или 29  \n\nПример: 25-31 автоматически станет в апреле 25–30 (до конца месяца).\n\nПоэтому, если вам необходимо указать, что дедлайн в конце каждого месяца, ставьте 31 число.\n</blockquote>'),
(554, 'telegram_choose_repeat_type', 'ru', '<b>Тип повторений</b>\n<i>Выберите подходящий вариант или нажмите \"Пропустить\", если он уже указан и вас устраивает</i>\n\n🔁 <i>Через N дней</i> — фиксированный интервал  \n📅 <i>Еженедельно</i> — по дням недели  \n🗓️ <i>Ежемесячно</i> — по числам месяца  \n📊 <i>Ежеквартально</i> — раз в квартал  \n🎂 <i>Ежегодно</i> — раз в год\n\n<blockquote expandable>\n<b>Подробнее <i>(нажмите для раскрытия)</i>:</b>\n🔁 Через каждые N дней\nЗадача повторяется через фиксированный промежуток дней.\n👉 Пример: «Принимать таблетки через 2 дня»\nЕсли хотите напоминание каждый день, N нужно будет на следующем шаге указать как 0.\n\n📅 Еженедельно\nЗадача повторяется по определённым дням недели.\n👉 Пример: «Ходить в спортзал по Пн, Ср и Пт»\n\n🗓️ Ежемесячно\nЗадача повторяется в определённые числа каждого месяца.\n👉 Пример: «Оплачивать коммуналку 10-го числа»\n\n📊 Ежеквартально\nЗадача повторяется раз в квартал, в определённый месяц и день.\n👉 Пример: «Сдавать отчётность 25-го числа первого месяца квартала»\n\n🎂 Ежегодно\nЗадача повторяется раз в год, в тот же день и месяц.\n👉 Пример: «Поздравить друга с днём рождения 5 сентября»\n</blockquote>\n'),
(555, 'telegram_choose_month_in_quarter', 'ru', '<b>Месяц в квартале</b>\r\n<i>Выберите месяц квартала, в котором наступит дедлайн.</i>'),
(556, 'telegram_choose_start_month_in_quarter', 'ru', '<b>Месяц в квартале</b>\r\n<i>Выберите месяц квартала, в котором начнётся период</i>'),
(557, 'telegram_choose_end_month_in_quarter', 'ru', '<b>Месяц в квартале</b>\r\n<i>Выберите месяц квартала, в котором закончится период выполнения.</i>'),
(558, 'telegram_enter_day_in_end_quarter_month', 'ru', '<b>День в месяце квартала</b>\r\n<i>Введите номер дня в выбранном на предыдущем шаге месяце</i>\r\n\r\n<i>Если нужен последний день месяца, введите 31</i>'),
(559, 'telegram_enter_day_in_start_quarter_month', 'ru', '<b>День в месяце квартала</b>\r\n<i>Введите номер дня в выбранном на предыдущем шаге месяце</i>\r\n\r\n<i>Если нужен последний день месяца, введите 31</i>'),
(560, 'telegram_enter_day_in_quarter_month', 'ru', '<b>День в месяце квартала</b>\r\n<i>Введите номер дня в выбранном на предыдущем шаге месяце</i>\r\n\r\n<i>Если нужен последний день месяца, введите 31</i>'),
(561, 'telegram_choose_month_in_year', 'ru', '<b>Месяц дедлайна</b>\r\n<i>Выберите месяц в году (от 1 до 12)</i>'),
(562, 'telegram_choose_end_month_in_year', 'ru', '<b>Месяц конца периода</b>\r\n<i>Выберите месяц в году (от 1 до 12)</i>'),
(563, 'telegram_choose_start_month_in_year', 'ru', '<b>Месяц начала периода</b>\n<i>Выберите месяц в году (от 1 до 12)</i>'),
(564, 'telegram_enter_day_in_year_month', 'ru', '<b>День дедлайна</b>\r\n<i>Введите номер дня месяца, к которому нужно выполнить задачу</i>'),
(565, 'telegram_enter_day_in_end_year_month', 'ru', '<b>День окончания периода</b>\r\n<i>Введите номер дня месяца, когда завершится задача или событие</i>'),
(566, 'telegram_enter_day_in_start_year_month', 'ru', '<b>День начала периода</b>\r\n<i>Введите номер дня месяца, когда начнется задача или событие</i>'),
(567, 'wrong_day_format', 'ru', 'Неверный формат дня: должно быть число от 1 до 31.'),
(568, 'telegram_wrong_day_format', 'ru', '<i>Неверный формат дня: должно быть число от 1 до 31.</i>'),
(569, 'telegram_wrong_data_use_buttons', 'ru', '<i>Переданы неверные данные. Воспользуйтесь кнопками.</i>'),
(570, 'task_dat', 'ru', 'Задаче'),
(571, 'event_dat', 'ru', 'Событию'),
(572, 'telegram_task_enter_search', 'ru', '<b>Поиск задач и событий</b>\r\n<i>Введите слово или фразу из названия, описания, напоминаний или тегов и отправьте.</i>\r\n\r\n<i>Или нажмите на кнопку «Показать все» — выведутся все актуальные задачи и события (по {#AMOUNT#} на страницу).</i>'),
(573, 'telegram_wrong_number_on_page', 'ru', '<i>Неверный номер элемента на странице.</i>'),
(574, 'telegram_tasks_show', 'ru', '<b>Все задачи и события</b>\r\n<i>Введите и отправьте номер из списка ниже или листайте страницы кнопками</i>\r\n\r\n<b>Страница {#PAGE#}/{#MAXPAGE#}</b>\r\n\r\n{#TASKS#}\r\n\r\n\r\n'),
(575, 'telegram_too_short_search_message', 'ru', '<i>Слишком короткий текст для поиска. Минимальное количество символов: 3.</i>'),
(576, 'telegram_no_tasks_found', 'ru', '<i>Не найдено ни одной задачи/события...</i>'),
(577, 'telegram_task_found', 'ru', '<b>{#TYPE#}</b> <i>({#SUBTYPE#})</i>\r\n\r\n<i>Название:</i> \"{#TITLE#}\".\r\n{#DESCRIPTION#}{#TAGS#}{#DEADLINE#}{#REPEAT#}{#REMINDERS#}\r\n\r\n<b><i>Выберите действие ниже</i></b>'),
(578, 'telegram_editing_task', 'ru', '<b>Редактирование {#TYPE#}</b> (<i>{#SUBTYPE#}</i>)\n<i>Выберите, что хотите изменить</i>\n\n<b>Название:</b> {#TITLE#}{#DESCRIPTION#}{#TAGS#}{#REPEATING#}{#NEAREST#}{#REMINDERS#}\n\n<i>Выберите теперь, что вы хотите отредактировать через кнопки ниже.</i>'),
(579, 'empty_value', 'ru', 'отсутствует'),
(580, 'telegram_empty_value', 'ru', '<i>отсутствует</i>'),
(581, 'empty_value_pl', 'ru', 'отсутствуют'),
(582, 'telegram_empty_value_pl', 'ru', '<i>отсутствуют</i>'),
(583, 'telegram_task_change_name', 'ru', '<b>Редактирование названия</b>\n\n<i>Текущее название:</i> \"{#TITLE#}\"\n\n<i>Введите новое название и отправьте боту</i>'),
(584, 'repeat_type', 'ru', 'Тип повторений'),
(585, 'telegram_repeat_type', 'ru', '<i>Тип повторений</i>'),
(586, 'telegram_daily_n_choosen', 'ru', '<i>Тип повторений:</i> через {#DAYS#} дней (то есть в промежутках между {#TYPE#} будет {#DAYS#} пустых дней)'),
(587, 'telegram_task_change_description_2', 'ru', '<b>Редактирование описания</b>\r\n\r\nТекущее описание: {#DESCRIPTION#}\r\n\r\n<i>Введите новое название и отправьте боту</i>'),
(588, 'telegram_add_tags_additional', 'ru', '<b>Добавление тегов</b>\r\n\r\n<i>Введите новые теги через запятую или с новой строки и отправьте. Текущие будут сохранены</i>\r\n\r\n<b>Текущие:</b> {#TAGS#}'),
(589, 'telegram_edit_repeating_type', 'ru', '<b>Редактирование повторяемости</b>\r\n<i>Выберите, будет задача/событие одноразовой или повторяющейся</i>\r\n\r\n🎯 <b>Одноразовая</b> — наступает один раз  \r\n👉 Пример: «Сходить ко врачу 10 октября в 15:00»\r\n\r\n🔁 <b>Повторяющаяся</b> — создаётся по алгоритму (через n дней, по дням недели или числам месяца)  \r\n👉 Пример: «Передавать показания счётчиков с 18 по 22 число каждого месяца»\r\n\r\n<i>Ваш текущий вариант</i>: {#TYPE#}'),
(590, 'telegram_edit_reminders', 'ru', '<b>Редактирование напоминаний</b>\n\n<i>Выберите действие ниже</i>'),
(591, 'telegram_task_was_updated', 'ru', '<b>Вы обновили {#TYPE#}</b> <i>({#SUBTYPE#})</i>\n\n<i>Название:</i> \"{#TITLE#}\".\n{#DESCRIPTION#}{#TAGS#}{#DEADLINE#}{#REPEAT#}{#REMINDERS#}'),
(592, 'telegram_confirm_deleting_task', 'ru', '<b>Подтвердите удаление {#TYPE#}</b> (<i>{#SUBTYPE#}</i>)\r\n\r\n<i>Название</i>: \"{#TITLE#}\"{#DESCRIPTION#}{#TAGS#}{#REMINDERS#}'),
(593, 'telegram_task_was_deleted_successfully', 'ru', '<b>Объект удалён</b>\r\n\r\n<i>{#TYPE#} ({#SUBTYPE#})</i>\r\n\r\n<b>Название:</b> {#TITLE#}{#DESCRIPTION#}{#TAGS#}{#REMINDERS#}'),
(594, 'task_remind', 'ru', 'Напоминание о задаче: «{#TITLE#}»{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#} \r\n\r\nОтметьте, что она увидена вами или выполнена, или перенесите напоминание на позже. Если этого не сделать, я напомню вам ещё через 15 минут.'),
(595, 'telegram_task_remind_second', 'ru', '<b>Повторное напоминание</b>\n<i>Задача:</i> «{#TITLE#}»{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\n\n<i>Отметьте задачу выполненной или перенесите напоминание.</i>\n<i>Если ничего не сделать, я напомню ещё раз через 15 минут.</i>'),
(596, 'telegram_task_remind_third', 'ru', '<b>Повторное напоминание</b>\n<i>Задача:</i> «{#TITLE#}»{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\n\n<i>Отметьте задачу выполненной или перенесите напоминание.</i>\n\n<i>Чтобы не пропускать важные напоминания, можно подключить платный тариф — тогда я смогу звонить на ваш номер даже без интернета.</i>'),
(597, 'telegram_task_remind_second_call', 'ru', '<b>Повторное напоминание</b>\n<i>Задача:</i> «{#TITLE#}»\n{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\n\n<i>Отметьте задачу выполненной или перенесите напоминание.</i>\n<i>Если ничего не сделать, я напомню ещё раз через 15 минут звонком на ваш телефон.</i>'),
(598, 'task_remind_call', 'ru', 'Последнее третье напоминание о задаче по вашему установленному напоминанию: «{#TITLE#}»{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\r\n\r\nОтметьте, что оно увидено вами, или перенесите напоминание на позже.\r\n\r\nВам также был направлен звонок.'),
(599, 'telegram_task_remind_call', 'ru', '<b>Повторное напоминание</b>\n<i>Задача:</i> «{#TITLE#}»\n{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\n\n<i>Отметьте задачу выполненной или перенесите напоминание.</i>\n<b>Вам также был направлен звонок.</b>\n'),
(600, 'task_to_call_query', 'ru', 'Нужно уведомить пользователя о задаче голосовым напоминанием (звонком).\n\nПреобразуй текст задачи ниже в текст для голосового звонка, который начитывается со скоростью 1,8 слова в секунду и читается не более 45 секунд.\n\nВыдели только основную суть задачи и срок.\nПопроси еще отметить выполненность напоминания в телеграме или перенести напоминание (не звонок!) на позже.\n\nНачни текст строго так:\n«Привет. Это приложение \"Ёж ап\".»\n\nТы говоришь женским голосом и от первого лица (используй формулировки «я напоминаю», «у тебя есть задача»). \n\nУ пользователя сейчас {#DAYTIME#}, поэтому пожелай ему в конце что-нибудь хорошее. Ни в коем случае не говори, что это последнее напоминание на сегодня, эта информация неизвестна.\n\nЕсли есть время с часами и минутами во времени дедлайна, то посчитай и скажи через сколько срок задачи подойдет к концу, если дедлайн наступит в ближайшие несколько часов. Если больше 6 часов до дедлайна, то не считай, просто напомни про время конца задачи (если оно указано).\n\nДанные задачи:\n- Название задачи: {#TITLE#}\n- Описание задачи: {#DESCRIPTION#}\n- Время дедлайна: {#TIME#}\n- Сейчас у пользователя: {#CURRENT_TIME#}\n- Пользователь написал для напоминания дополнительный текст: {#REMIND#}\n\nВерни ответ в json: {\"text\": \"\"}'),
(601, 'event_to_call_query', 'ru', 'Нужно уведомить пользователя о событии голосовым напоминанием (звонком).\n\nПреобразуй текст события ниже в текст для голосового звонка, который начитывается со скоростью 1,8 слова в секунду и читается не более 45 секунд.\n\nВыдели только основную суть события и дату начала.\nПопроси еще отметит в телеграме, что он получил уведомление, или перенести напоминание (не звонок!) на позже.\n\nНачни текст строго так:\n«Привет. Это приложение \"Ёж ап\".»\n\nТы говоришь женским голосом и от первого лица (используй формулировки «я напоминаю», «у тебя запланировано событие» и т.п., не обязательно слово в слово, можешь для разнообразия варьировать, менять формулировки на свое усмотрение). \n\nУ пользователя сейчас {#DAYTIME#}, поэтому пожелай ему в конце что-нибудь хорошее. Ни в коем случае не говори, что это последнее напоминание на сегодня, эта информация неизвестна.\n\nЕсли есть время с часами и минутами во времени начала, то посчитай и скажи через сколько начнется событие, если оно произойдет в ближайшие несколько часов. Если больше 6 часов до события, то не считай, просто напомни про время начала (если оно указано)\n\nДанные события:\n- Название события: {#TITLE#}\n- Описание события: {#DESCRIPTION#}\n- Время начала: {#TIME#}\n- Сейчас у пользователя: {#CURRENT_TIME#}\n- Пользователь написал для напоминания дополнительный текст: {#REMIND#}\n\nВерни ответ в json: {\"text\": \"\"}\n'),
(602, 'unknown', 'ru', 'неизвестно'),
(603, 'morning', 'ru', 'утро'),
(604, 'day', 'ru', 'день'),
(605, 'evening', 'ru', 'вечер'),
(606, 'night', 'ru', 'ночь'),
(608, 'telegram_event_remind', 'ru', '<b>Напоминание</b>\n<i>Событие:</i> «{#TITLE#}»{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\n\n<i>Отметьте событие выполненным или перенесите напоминание.</i>\n<i>Если ничего не сделать, я напомню ещё раз через 15 минут.</i>'),
(609, 'telegram_event_remind_second', 'ru', '<b>Повторное напоминание</b>\r\n<i>Событие:</i> «{#TITLE#}»{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\r\n\r\n<i>Отметьте событие выполненным или перенесите напоминание.</i>\r\n<i>Если ничего не сделать, я напомню ещё раз через 15 минут.</i>'),
(610, 'telegram_event_remind_third', 'ru', '<b>Повторное напоминание</b>\r\n<i>Событие:</i> «{#TITLE#}»{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\r\n\r\n<i>Отметьте событие выполненным или перенесите напоминание.</i>\r\n\r\n<i>Чтобы не пропускать важные напоминания, можно подключить платный тариф — тогда я смогу звонить на ваш номер и напоминать даже без интернета.</i>'),
(611, 'telegram_event_remind_second_call', 'ru', '<b>Повторное напоминание</b>\n<i>Событие:</i> «{#TITLE#}»\n{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\n\n<i>Отметьте событие выполненным или перенесите напоминание.</i>\n<i>Если ничего не сделать, я напомню ещё раз через 15 минут звонком на ваш телефон.</i>'),
(612, 'event_remind_call', 'ru', 'Последнее третье напоминание о событии по вашему установленному напоминанию: «{#TITLE#}»{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\r\n\r\nОтметьте, что оно увидено вами, или перенесите напоминание на позже.\r\n\r\nВам также был направлен звонок.'),
(613, 'telegram_event_remind_call', 'ru', '<b>Повторное напоминание</b>\n<i>Событие:</i> «{#TITLE#}»\n{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\n\n<i>Отметьте событие выполненным или перенесите напоминание.</i>\n<b>Вам также был направлен звонок.</b>\n'),
(614, 'telegram_task_remind_call_repeat', 'ru', '<b>Повторное напоминание</b>\r\n<i>Задача:</i> «{#TITLE#}»\r\n{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\r\n\r\n<i>Отметьте задачу выполненной или перенесите напоминание.</i>\r\n<b>Вам также был направлен повторный звонок.</b>\r\n'),
(615, 'telegram_event_remind_call_repeat', 'ru', '<b>Повторное напоминание</b>\n<i>Событие:</i> «{#TITLE#}»\n{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\n\n<i>Отметьте событие выполненным или перенесите напоминание.</i>\n<b>Вам также был направлен повторный звонок.</b>\n'),
(616, 'remind_wish', 'ru', 'Пользователь для напоминания написал следующее'),
(617, 'text_empty', 'ru', 'текст отсутствует'),
(618, 'telegram_event_remind_call_fail', 'ru', '<b>Повторное напоминание</b>\r\n<i>Событие:</i> «{#TITLE#}»\r\n{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\r\n\r\n<i>Отметьте событие выполненным или перенесите напоминание.</i>\r\n<b>Мы не смогли вам дозвониться.</b>\r\n'),
(619, 'telegram_task_remind_call_fail', 'ru', '<b>Повторное напоминание</b>\r\n<i>Задача:</i> «{#TITLE#}»\r\n{#DESCRIPTION#}{#REMIND#}{#LIST#}{#TAGS#}\r\n\r\n<i>Отметьте задачу выполненной или перенесите напоминание.</i>\r\n<b>Мы не смогли вам дозвониться.</b>\r\n'),
(620, 'telegram_event_was_created', 'ru', '<b>{#TYPE#} создано</b> <i>({#SUBTYPE#})</i>\r\n\r\n<i>Название:</i> \"{#TITLE#}\".\r\n{#DESCRIPTION#}{#TAGS#}{#DEADLINE#}{#REPEAT#}{#REMINDERS#}\r\n'),
